DROP INDEX IF EXISTS idx_agent_job_delivery_dedup;

CREATE INDEX idx_agent_job_delivery_dedup
ON agent_job (workspace_id, (metadata->>'pull_request_id'), completed_at DESC)
WHERE delivery_status = 'DELIVERED'
  AND job_type = 'PULL_REQUEST_REVIEW'
  AND delivery_comment_id IS NOT NULL;
